const raw = $input.first().json;
const arr = Array.isArray(raw) ? raw : (raw.items || raw.data || [raw]);

if (!arr || arr.length === 0) {
  return [{ json: { respuesta_texto: '⚠️ No se encontraron videos recientes. Intenta más tarde.', producto_url: '' } }];
}

// Filtro de contenido: excluir videos que hablan del negocio en vez de mostrar un producto
const excluir = ['dropshipping', 'dropship', 'wholesale', 'reseller', 'ecommerce', 'how to sell', 'como vender', 'negocio online', 'make money', 'ganar dinero', 'shopify tutorial', 'print on demand', 'curso', 'mentoria'];

// Filtro de fecha: últimas 2 semanas (respaldo por si searchDatePosted no filtra todo)
const dosSemanas = Date.now() / 1000 - 14 * 24 * 60 * 60;

const filtrados = arr.filter(v => {
  if ((v.createTime || 0) < dosSemanas) return false;
  const todoTexto = ((v.text || '') + ' ' + (v.hashtags || []).map(h => h.name || h).join(' ')).toLowerCase();
  if (excluir.some(p => todoTexto.includes(p))) return false;
  return true;
});

if (filtrados.length === 0) {
  return [{ json: { respuesta_texto: '⚠️ No encontré productos virales recientes (últimas 2 semanas). Prueba mañana.', producto_url: '' } }];
}

filtrados.sort((a, b) => (b.playCount || 0) - (a.playCount || 0));
const top = filtrados[0];

const autor = top.authorMeta?.name || top.authorMeta?.nickName || 'N/D';
const url = top.webVideoUrl || '';
const fecha = top.createTimeISO ? top.createTimeISO.slice(0, 10) : 'N/D';

return [{ json: {
  respuesta_texto: `🔥 *TOP VIRAL ENCONTRADO* 🔥\n\n📺 *Vistas:* ${top.playCount || 'N/D'}\n❤️ *Likes:* ${top.diggCount || 'N/D'}\n📤 *Compartidos:* ${top.shareCount || 'N/D'}\n🔖 *Guardados:* ${top.collectCount || 'N/D'}\n📅 *Fecha:* ${fecha}\n👤 *Autor:* @${autor}\n🔗 *Link TikTok:* ${url || 'No disponible'}\n\n_¿Lo aprobamos?_ 👇`,
  producto_url: url
} }];
